use std::io;


fn read_line() -> String {
    let mut input_line = String::new();
    io::stdin().read_line(&mut input_line).unwrap();
    return String::from(input_line.trim());
}

enum Protocol { HTTP, FTP }

fn fix_protocol(s: &String) -> (String, Protocol) {
    let mut res: String = String::new();
    if s.chars().nth(0) == Some('f') {
        (s.chars().skip(3).collect(), Protocol::FTP)
    } else {
        (s.chars().skip(4).collect(), Protocol::HTTP)
    }
}



